fs.writeFileSync(path.join(root, 'USER_OWNERSHIP_PATCH_README.txt'), readme, 'utf8');
console.log('Done successfully.');
console.log('Backup directory:', backupDir);
console.log('Readme created: USER_OWNERSHIP_PATCH_README.txt');
